// Simulated: fetch upcoming appointments for next 24-48 hours
// In production, this would query the EHR/scheduling system
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);

const appointments = [
  {
    appointmentId: 'apt-001',
    patientPhone: '+1234567890',
    patientFirstName: 'Patient',
    appointmentDate: tomorrow.toISOString().split('T')[0],
    appointmentTime: '09:00',
    providerName: 'Dr. Smith',
    appointmentType: 'Follow-up',
    location: 'Main Office'
  }
];

return appointments.map(apt => ({ json: apt }));

const apt = $input.first().json;

// Build reminder message (PHI-stripped — no last name, no medical details)
const message = `Hi ${apt.patientFirstName}, this is a reminder about your ${apt.appointmentType} appointment tomorrow at ${apt.appointmentTime} with ${apt.providerName} at ${apt.location}. Reply CONFIRM to confirm or call us to reschedule.`;

return [{ json: { ...apt, reminderMessage: message, channel: 'sms' } }];

// Placeholder for SMS/email sending
// In production: integrate Twilio for SMS, SendGrid for email
const data = $input.first().json;

console.log(`Would send ${data.channel} to ${data.patientPhone}: ${data.reminderMessage}`);

return [{ json: { success: true, appointmentId: data.appointmentId, channel: data.channel, sentAt: new Date().toISOString() } }];
